class SqrtDecomposition:
    function __init__(ARRAY):
        self.n = length(ARRAY)
        self.block_size = int(sqrt(self.n))
        self.blocks = [infinity] * ((self.n + self.block_size - 1) // self.block_size)

        for i in range(self.n):
            self.blocks[i // self.block_size] = min(self.blocks[i // self.block_size], ARRAY[i])

