            edge(node, heavyChild).type = HEAVY

    // Decompose into heavy paths
    paths = EMPTY_LIST
    for node in tree:
        if node.parent == NULL OR edge(node.parent, node).type == LIGHT:
            path = ExtractHeavyPath(node)
            paths.ADD(path)

    return paths
