FUNCTION JohnsonAllPairs(graph):
    // Add new vertex connected to all vertices with weight 0
    newGraph = AddSourceVertex(graph)

    // Run Bellman-Ford from new source
    h = BellmanFord(newGraph, newSource)
    if h == NULL:  // negative cycle detected
        return NULL

    // Reweight edges: w'(u,v) = w(u,v) + h[u] - h[v]
    reweightedGraph = ReweightEdges(graph, h)

    // Run Dijkstra from each vertex
    distances = 2D_ARRAY[V][V]
    for u = 0 to V-1:
        dist = Dijkstra(reweightedGraph, u)
        for v = 0 to V-1:
            // Convert back to original weights
            distances[u][v] = dist[v] + h[v] - h[u]

    return distances
